const trigger = $('workflow_trigger').first().json;
const genre = $('get_genre_config').first().json;
const genreData = Array.isArray(genre) ? genre[0] : genre;
const research = $('research_concept').first().json.message || '';
const chapterCount = parseInt(trigger.target_chapter_count) || 10;
const structureGuidelines = $('settings').first().json.story_structure_guidelines || '';

const prompt = `You are a master storyteller and book architect.

## Genre: ${genreData?.genre_name || 'Fiction'}
## Genre Guidelines: ${genreData?.writing_guidelines || ''}

## Writing Prime Directive
Write like a human, not a machine. Use clear, everyday language and short sentences. Cut cliches — no revolutionize, game-changing, unleash, or delve. Get to the point — remove filler words. No hype, just facts. Be genuine. Show, don't tell — use concrete examples instead of vague claims. Stay focused. Keep descriptions tight. Respect the reader's intelligence. Write like you'd pitch a story to a smart friend. Skip unnecessary adjectives and adverbs.

## Story Structure Guidelines
Use these guidelines to shape the plot architecture, character roles, and arc structure of the outline:

${structureGuidelines}

## Research
${research}

## Assignment
Create a detailed outline for "${trigger.project_title || 'Untitled'}".

Core concept: ${trigger.initial_concept}
Themes: ${trigger.themes || 'To be determined'}
Target chapters/sections: ${chapterCount}

## Requirements
Apply the Story Structure Guidelines above to design the plot. Choose the most appropriate structural model (Three-Act, Hero's Journey, Seven-Point, etc.) for this story's tone and genre, then build the outline using that model's beats. Include:
1. A refined title and one-paragraph premise
2. Core themes (3-5)
3. Character profiles with clearly assigned roles (Protagonist, Antagonist, Dynamic, Static) with name, role, arc, and description
4. Section/chapter breakdown (${chapterCount} entries) with:
   - Number and title
   - 2-3 sentence brief of what happens
   - Arc notes (which structural beat this represents, character development, theme progression)
   - Research topics to explore for this section

Return as JSON matching the output schema exactly.`;

return [{ json: { prompt } }];

const supabaseUrl = $('settings').first().json.SUPABASE_URL;
const apiKey = $('settings').first().json.SUPABASE_API_KEY;
const headers = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json', 'Prefer': 'return=representation' };
const trigger = $('workflow_trigger').first().json;
const outline = $input.first().json.output || {};
const title = outline.title || trigger.project_title || 'Untitled';
const genreSlug = trigger.genre_slug;

// Try to find existing project
let project = null;
try {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/rest/v1/writing_projects?title=eq.' + encodeURIComponent(title) + '&limit=1',
    headers: { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey }
  });
  if (Array.isArray(resp) && resp.length > 0 && resp[0].id) project = resp[0];
} catch (e) {}

if (project) {
  // Update existing
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: supabaseUrl + '/rest/v1/writing_projects?id=eq.' + project.id,
    headers,
    body: { outline: outline, genre_slug: genreSlug, updated_at: new Date().toISOString() }
  });
} else {
  // Create new
  const created = await this.helpers.httpRequest({
    method: 'POST',
    url: supabaseUrl + '/rest/v1/writing_projects',
    headers,
    body: { title, genre_slug: genreSlug, project_type: 'story', status: 'outlined', outline: outline, chapter_count: (outline.chapters || []).length }
  });
  project = Array.isArray(created) ? created[0] : created;
}

return [{ json: { outline, project_id: project?.id || null, title } }];
